467		wire := errorWire{
468			Code:    e.Code,
469			Message: e.Message,
470		}
471		if e.Data.ErrorClass != "" || len(e.Data.Detail) != 0 {
472			data, err := json.Marshal(e.Data)
473			if err != nil {
474				return nil, fmt.Errorf("adapterkit: marshal error data: %w", err)
475			}
476			wire.Data = data
477		}
478		return json.Marshal(wire)
479	}
