482		var wire errorWire
483		if err := json.Unmarshal(data, &wire); err != nil {
484			return fmt.Errorf("adapterkit: unmarshal error: %w", err)
485		}
486		e.Code = wire.Code
487		e.Message = wire.Message
488		e.Data = ErrorData{}
489		if len(wire.Data) != 0 && !bytes.Equal(wire.Data, []byte("null")) {
490			if err := json.Unmarshal(wire.Data, &e.Data); err != nil {
491				return fmt.Errorf("adapterkit: unmarshal error data: %w", err)
492			}
493		}
494		return nil
495	}
496	
497	func encodeOpContent(content []byte) (Encoding, string) {
498		if utf8.Valid(content) {
499			return EncodingUTF8, string(content)
500		}
501		return EncodingBase64, base64.StdEncoding.EncodeToString(content)
502	}
503	
504	func decodeOpContent(encoding Encoding, content string) ([]byte, error) {
505		switch encoding {
506		case EncodingUTF8:
507			return []byte(content), nil
508		case EncodingBase64:
509			decoded, err := base64.StdEncoding.DecodeString(content)
510			if err != nil {
511				return nil, fmt.Errorf("adapterkit: decode base64 content: %w", err)
512			}
513			return decoded, nil
514		case "":
515			return nil, ErrMissingEncoding
516		default:
517			return nil, fmt.Errorf("adapterkit: unknown encoding %q", encoding)
518		}
519	}
