	if len(content) > MaxOpPayloadBytes {
		return OpWriteFile{}, fmt.Errorf("%w: %d > %d", ErrPayloadTooLarge, len(content), MaxOpPayloadBytes)
	}
	return OpWriteFile{Path: path, Mode: mode, Content: content}, nil
}

