1	package adapter
2	
3	import (
4		"bytes"
5		"context"
6		"encoding/json"
7		"errors"
8		"fmt"
9		"path"
10		"regexp"
11		"strings"
12		"time"
13	
14		"github.com/aienvs/aienvs/internal/adapter/contract"
15	)
16	
17	// reWindowsVolumePrefix matches a leading drive letter ("C:", "d:", ...).
18	// Such a prefix is absolute on Windows when interpreted by OS path rules
19	// even though path.IsAbs (which uses POSIX rules) reports it as relative,
20	// so we reject it on every OS to keep declared-outputs gating safe
21	// regardless of host platform. Same shape used in
22	// manifest.ValidateReservedPrefix.
23	var reWindowsVolumePrefix = regexp.MustCompile(`\A[A-Za-z]:`)
24	
25	// Initialize sends the initialize request, validates the cookie echo
26	// and protocol version, and captures the adapter's declared_outputs +
27	// capabilities for later enforcement. After Initialize returns
28	// successfully, the session is ready for Initialized + Emit.
29	func (s *AdapterSession) Initialize(ctx context.Context) (*contract.InitializeResult, error) {
30		if s.state != sessionStateNew {
31			return nil, &RuntimeError{
32				Class: contract.ErrorClassAdapterProtocolOrder,
33				Err:   fmt.Errorf("%w: Initialize called from state %d", ErrAdapterProtocolOrderViolation, s.state),
34			}
35		}
36	
37		timeout := resolveTimeouts(s.options.Timeouts).Handshake
38		rctx, cancel := context.WithTimeout(ctx, timeout)
39		defer cancel()
40	
41		id := s.ids.Next()
42		s.ids.MarkPending(id, contract.MethodInitialize)
43	
44		params := contract.InitializeParams{
45			Client:           "aienvs",
46			ProtocolVersions: []string{ContractVersionV1},
47			Cookie:           s.cookie,
48			WorkspaceRoot:    s.options.WorkspaceRoot,
49			ReservedPrefix:   s.adapter.Manifest.ReservedPrefix,
50			IRVersion:        s.options.IRVersion,
51		}
52	
53		resp, err := s.requestResponse(rctx, id, contract.MethodInitialize, params, contract.MethodInitialize, timeout)
54		if err != nil {
55			s.ids.Cancel(id)
56			return nil, err
57		}
58	
59		var result contract.InitializeResult
60		if err := json.Unmarshal(resp.Result, &result); err != nil {
61			return nil, &RuntimeError{
62				Class: contract.ErrorClassAdapterPanic,
63				Err:   fmt.Errorf("decode initialize result: %w", err),
64			}
65		}
66	
67		// Cookie validation: bundled adapters skip (they share process).
68		// Subprocess adapters MUST echo the cookie verbatim. The cookie
69		// itself never appears in the error message — leaking it would
70		// undermine the auth boundary it exists to enforce.
71		if s.adapter.Source != SourceBundled {
72			echoed := extractCookieFromResult(resp.Result)
73			if echoed == "" {
74				return nil, &RuntimeError{
75					Class: contract.ErrorClassAdapterExecDenied,
76					Err:   ErrAdapterCookieMissing,
77				}
78			}
79			if echoed != s.cookie {
80				return nil, &RuntimeError{
81					Class: contract.ErrorClassAdapterExecDenied,
82					Err:   ErrAdapterCookieMismatch,
83				}
84			}
85		}
86	
87		if result.ProtocolVersion != ContractVersionV1 {
88			return nil, &RuntimeError{
89				Class: contract.ErrorClassAdapterProtocolMismatch,
90				Err:   fmt.Errorf("%w: adapter speaks %q (want %q)", ErrAdapterProtocolMismatch, result.ProtocolVersion, ContractVersionV1),
91			}
92		}
93	
94		// Record which kinds were declared "supported" — used by
95		// capability-lied detection after Emit.
96		for kind, level := range result.Capabilities.ConceptKinds {
97			if level == contract.CapabilitySupported {
98				s.gateChecks[contract.OpKind(kind)] = true
99			}
100		}
101	
102		s.initResult = &result
103		s.state = sessionStateInitialized
104		return &result, nil
105	}
106	
107	// Initialized sends the initialized notification. After this returns,
108	// the session is ready for Emit. The notification has no response;
109	// any error here is purely the wire-level send failure.
110	func (s *AdapterSession) Initialized(ctx context.Context) error {
111		if s.state != sessionStateInitialized {
112			return &RuntimeError{
113				Class: contract.ErrorClassAdapterProtocolOrder,
114				Err:   fmt.Errorf("%w: Initialized called from state %d", ErrAdapterProtocolOrderViolation, s.state),
115			}
116		}
117		notification := contract.Notification{Method: contract.MethodInitialized}
118		payload, err := json.Marshal(notification)
119		if err != nil {
120			return &RuntimeError{
121				Class: contract.ErrorClassAdapterPanic,
122				Err:   fmt.Errorf("marshal initialized notification: %w", err),
123			}
124		}
125		if err := s.transport.Send(ctx, payload); err != nil {
126			return classifySendError(err)
127		}
128		return nil
129	}
130	
131	// Emit sends the emit request for one target with the given IR, then
132	// reads the streamed ops + final response. Each op is checked against
133	// the declared_outputs gate; any violation cancels the session.
134	//
135	// IR is supplied as json.RawMessage to keep this package decoupled
136	// from internal/ir.
137	func (s *AdapterSession) Emit(ctx context.Context, target string, ir json.RawMessage) (*contract.EmitResult, error) {
138		if s.state != sessionStateInitialized && s.state != sessionStateEmitting {
139			return nil, &RuntimeError{
140				Class: contract.ErrorClassAdapterProtocolOrder,
141				Err:   fmt.Errorf("%w: Emit called from state %d", ErrAdapterProtocolOrderViolation, s.state),
142			}
143		}
144		s.state = sessionStateEmitting
145	
146		timeout := resolveTimeouts(s.options.Timeouts).Emit
147		rctx, cancel := context.WithTimeout(ctx, timeout)
148		defer cancel()
149	
150		id := s.ids.Next()
151		s.ids.MarkPending(id, contract.MethodEmit)
152	
153		params := contract.EmitParams{
154			Target: target,
155			IR:     ir,
156		}
157	
158		resp, err := s.requestResponse(rctx, id, contract.MethodEmit, params, contract.MethodEmit, timeout)
159		if err != nil {
160			s.ids.Cancel(id)
161			return nil, err
162		}
163	
164		var result contract.EmitResult
165		if err := json.Unmarshal(resp.Result, &result); err != nil {
166			return nil, &RuntimeError{
167				Class: contract.ErrorClassAdapterPanic,
168				Err:   fmt.Errorf("decode emit result: %w", err),
169			}
170		}
171	
172		// Declared-outputs integrity gate. Each performed op must target a
173		// path inside one of the declared outputs. Warnings are exempt
174		// (concept-level, no path).
175		nonWarningOps := 0
176		for i, op := range result.OpsPerformed {
177			if op.Op == contract.OpKindWarning {
178				continue
179			}
180			nonWarningOps++
181			if !s.pathInDeclaredOutputs(op.Path) {
182				return nil, &RuntimeError{
183					Class: contract.ErrorClassAdapterUndeclaredOutput,
184					Err: fmt.Errorf("%w: op[%d] kind=%s path=%q",
185						ErrAdapterUndeclaredOutput, i, op.Op, op.Path),
186				}
187			}
188		}
189	
190		// Capability-lied detection: if the adapter declared any kind as
191		// "supported" in initialize and the IR contained nodes of those
192		// kinds, then the adapter must have emitted at least one
193		// non-warning op. An adapter that says "yes, I handle X" and then
194		// silently does nothing is a worse failure mode than a "won't
195		// handle X" honest decline — silent nullification breaks the
196		// determinism guarantee.
197		if nonWarningOps == 0 && irContainsSupportedKind(ir, s.gateChecks) {
198			return nil, &RuntimeError{
199				Class: contract.ErrorClassAdapterCapabilityLied,
200				Err:   ErrAdapterCapabilityLied,
201			}
202		}
203	
204		return &result, nil
205	}
206	
207	// irContainsSupportedKind reports whether the IR has at least one node
208	// whose kind appears in the supported set. Best-effort: a malformed IR
209	// returns false (no false positives — better to under-report than to
210	// flag a legitimate adapter for what is really a runtime bug).
211	//
212	// The IR is scanned with a streaming decoder so a large IR doesn't
213	// force a full unmarshal into memory. We walk the top-level object
214	// looking for a "nodes" array, then decode one element at a time into
215	// a small struct that only captures the "kind" field — short-circuiting
216	// on the first supported match.
217	func irContainsSupportedKind(ir json.RawMessage, supported map[contract.OpKind]bool) bool {
218		if len(supported) == 0 {
219			return false
220		}
221		dec := json.NewDecoder(bytes.NewReader(ir))
222	
223		// Expect the document to open with "{".
224		tok, err := dec.Token()
225		if err != nil {
226			return false
227		}
228		if d, ok := tok.(json.Delim); !ok || d != '{' {
229			return false
230		}
231	
232		// Walk top-level keys. For "nodes", drop into the array and scan
233		// elements one at a time. For everything else, skip the value.
234		for dec.More() {
235			keyTok, err := dec.Token()
236			if err != nil {
237				return false
238			}
239			key, ok := keyTok.(string)
240			if !ok {
241				return false
242			}
243			if key != "nodes" {
244				if err := skipJSONValue(dec); err != nil {
245					return false
246				}
247				continue
248			}
249			// Expect "[".
250			tok, err := dec.Token()
251			if err != nil {
252				return false
253			}
254			if d, ok := tok.(json.Delim); !ok || d != '[' {
255				return false
256			}
257			for dec.More() {
258				var node struct {
259					Kind string `json:"kind"`
260				}
261				if err := dec.Decode(&node); err != nil {
262					return false
263				}
264				if supported[contract.OpKind(node.Kind)] {
265					return true
266				}
267			}
268			// Consume the closing "]". After "nodes" there's nothing else
269			// we need from the IR; done either way.
270			if _, err := dec.Token(); err != nil {
271				return false
272			}
273			return false
274		}
275		return false
276	}
277	
278	// skipJSONValue consumes the next JSON value from dec (object, array,
279	// or scalar) and discards it. Used to skip top-level fields that
280	// irContainsSupportedKind does not care about without buffering them.
281	func skipJSONValue(dec *json.Decoder) error {
282		tok, err := dec.Token()
283		if err != nil {
284			return err
285		}
286		d, ok := tok.(json.Delim)
287		if !ok {
288			// Scalar — already consumed.
289			return nil
290		}
291		if d != '{' && d != '[' {
292			return fmt.Errorf("unexpected delimiter %q", d)
293		}
294		depth := 1
295		for depth > 0 {
296			t, err := dec.Token()
297			if err != nil {
298				return err
299			}
300			if dd, ok := t.(json.Delim); ok {
301				switch dd {
302				case '{', '[':
303					depth++
304				case '}', ']':
305					depth--
306				}
307			}
308		}
309		return nil
310	}
311	
312	// Shutdown sends the shutdown request and tears down the transport.
313	// Returns the classified termination error (nil for clean exit).
314	//
315	// Shutdown is the terminal phase — after it returns, the session is
316	// finalized and no further methods may be called.
317	func (s *AdapterSession) Shutdown(ctx context.Context) error {
318		switch s.state {
319		case sessionStateClosed:
320			return nil
321		case sessionStateNew:
322			// Shutdown without Initialize: just tear down the transport.
323			s.state = sessionStateClosed
324			return s.transport.Close(ctx)
325		}
326	
327		timeout := resolveTimeouts(s.options.Timeouts).Shutdown
328		rctx, cancel := context.WithTimeout(ctx, timeout)
329		defer cancel()
330	
331		id := s.ids.Next()
332		s.ids.MarkPending(id, contract.MethodShutdown)
333	
334		params := contract.ShutdownParams{}
335		_, err := s.requestResponse(rctx, id, contract.MethodShutdown, params, contract.MethodShutdown, timeout)
336		if err != nil {
337			s.ids.Cancel(id)
338			// Don't return here; still tear down the transport so the
339			// process exits. Log the error via the closeErr.
340		} else {
341			// Protocol-level shutdown succeeded. Inform the transport so
342			// its Close path knows to treat any non-zero exit as expected.
343			// Without this signal, an adapter that returns from main with
344			// a non-zero status after responding to shutdown would surface
345			// as a SubprocessExitError, which would mis-classify a clean
346			// shutdown as a fault.
347			s.transport.MarkProtocolShutdownAcked()
348		}
349	
350		closeErr := s.transport.Close(ctx)
351	
352		// Any ids still pending here have been abandoned: the adapter
353		// returned an error or the transport was torn down before a
354		// response arrived. Failed requests are explicitly removed with
355		// Cancel(id), and any ids still pending at this point will be
356		// dropped with the IDCorrelator when this session is closed, so
357		// retention is bounded by session lifetime rather than by a
358		// max-pending eviction policy.
359	
360		s.state = sessionStateClosed
361	
362		if err != nil {
363			return err
364		}
365		if closeErr != nil {
366			return classifyTransportError(closeErr)
367		}
368		return nil
369	}
370	
371	// requestResponse sends a request, waits for the matching response,
372	// and returns it. Honors ctx for cancellation. Errors are wrapped in
373	// RuntimeError with the appropriate ErrorClass.
374	//
375	// phase identifies the lifecycle phase for error messages (initialize,
376	// emit, shutdown). phaseTimeout is the per-phase deadline so a timeout
377	// error reports the correct duration — without this, a 5s handshake
378	// timeout was being reported as "exceeded 30s" because the runtime
379	// always read its handshake timeout for the message.
380	func (s *AdapterSession) requestResponse(ctx context.Context, id contract.ID, method string, params interface{}, phase string, phaseTimeout time.Duration) (*contract.Message, error) {
381		paramsRaw, err := json.Marshal(params)
382		if err != nil {
383			return nil, &RuntimeError{
384				Class: contract.ErrorClassAdapterPanic,
385				Err:   fmt.Errorf("marshal %s params: %w", method, err),
386			}
387		}
388	
389		req := contract.Request{
390			ID:     id,
391			Method: method,
392			Params: paramsRaw,
393		}
394		payload, err := json.Marshal(req)
395		if err != nil {
396			return nil, &RuntimeError{
397				Class: contract.ErrorClassAdapterPanic,
398				Err:   fmt.Errorf("marshal %s envelope: %w", method, err),
399			}
400		}
401	
402		if err := s.transport.Send(ctx, payload); err != nil {
403			return nil, classifySendError(err)
404		}
405	
406		// Read the matching response. v1 doesn't allow adapter→runtime
407		// requests or notifications outside the initialized notification
408		// (which flows runtime→adapter), so we expect exactly one frame
409		// in response. Interleaved progress notifications are an 8b feature.
410		raw, err := s.transport.Recv(ctx)
411		if err != nil {
412			if errors.Is(err, context.DeadlineExceeded) {
413				return nil, &RuntimeError{
414					Class: contract.ErrorClassAdapterTimeout,
415					Err:   fmt.Errorf("%w: %s exceeded %s", ErrAdapterTimeout, phase, phaseTimeout),
416				}
417			}
418			return nil, classifyTransportError(err)
419		}
420		msg, err := contract.ParseMessage(raw)
421		if err != nil {
422			return nil, &RuntimeError{
423				Class: contract.ErrorClassAdapterPanic,
424				Err:   fmt.Errorf("parse message: %w", err),
425			}
426		}
427		if msg.Kind != contract.MessageKindResponse {
428			return nil, &RuntimeError{
429				Class: contract.ErrorClassAdapterPanic,
430				Err:   fmt.Errorf("%w: got %v while awaiting %s response", ErrAdapterUnexpectedMessage, msg.Kind, method),
431			}
432		}
433		if !msg.HasID || msg.ID.AsInt() != id.AsInt() {
434			return nil, &RuntimeError{
435				Class: contract.ErrorClassAdapterPanic,
436				Err:   fmt.Errorf("%w: response id mismatch (want %d)", ErrAdapterUnexpectedMessage, id.AsInt()),
437			}
438		}
439		_, _ = s.ids.Resolve(msg.ID)
440		if msg.Error != nil {
441			// Class is documented to always be populated. Adapters MAY omit
442			// the optional error_class data field; default to adapter-panic
443			// so callers never see an empty classifier.
444			class := msg.Error.Data.ErrorClass
445			if class == "" {
446				class = contract.ErrorClassAdapterPanic
447			}
448			return nil, &RuntimeError{
449				Class:        class,
450				Err:          fmt.Errorf("adapter returned error %d: %s", msg.Error.Code, msg.Error.Message),
451				AdapterError: msg.Error,
452			}
453		}
454		return &msg, nil
455	}
456	
457	// pathInDeclaredOutputs reports whether opPath is contained within
458	// one of the adapter's declared_outputs. Both sides are normalized
459	// with path.Clean before comparison so an adapter can't smuggle a
460	// path containing ".." or duplicate "/" segments through the gate.
461	//
462	// Returns false for empty paths (warnings exempt themselves at the
463	// caller), absolute paths (declared_outputs are workspace-relative),
464	// paths whose cleaned form starts with ".." (escapes the workspace),
465	// and paths containing a backslash or Windows volume prefix — those
466	// shapes are not absolute under path.IsAbs (which uses the forward-
467	// slash POSIX rules) but are absolute under OS path rules on Windows
468	// and would let an op escape the workspace once interpreted there.
469	func (s *AdapterSession) pathInDeclaredOutputs(opPath string) bool {
470		if opPath == "" {
471			return false
472		}
473		if s.initResult == nil {
474			return false
475		}
476		if path.IsAbs(opPath) {
477			return false
478		}
479		// Windows-safety: path.IsAbs ignores both backslash separators and
480		// drive-letter volume prefixes, so a path like "C:\\foo" or "..\\..\\etc"
481		// would slip past the relative-path gate above. Reject both shapes
482		// outright on every OS — they are never valid for a workspace-relative
483		// path on the wire, regardless of host platform.
484		if strings.ContainsRune(opPath, '\\') {
485			return false
486		}
487		if reWindowsVolumePrefix.MatchString(opPath) {
488			return false
489		}
490		clean := path.Clean(opPath)
491		if clean == ".." || strings.HasPrefix(clean, "../") {
492			return false
493		}
494		for _, decl := range s.initResult.DeclaredOutputs {
495			if decl.Path == "" {
496				continue
497			}
498			declClean := path.Clean(decl.Path)
499			if path.IsAbs(declClean) {
500				continue
501			}
502			// path.Clean turns "" or "./" into ".". A declared output of "."
503			// is the workspace root: every workspace-relative path is contained
504			// within it. Without this case the prefix check below would fail
505			// for any normalized path that doesn't literally start with "./".
506			if declClean == "." {
507				return true
508			}
509			if clean == declClean || strings.HasPrefix(clean, declClean+"/") {
510				return true
511			}
512		}
513		return false
514	}
515	
516	// classifySendError wraps a transport.Send error in a RuntimeError.
517	// Send failures are typically transport-level (process died, pipe
518	// closed); classify as adapter-panic. Free function — does not need
519	// session state.
520	func classifySendError(err error) *RuntimeError {
521		if errors.Is(err, context.DeadlineExceeded) {
522			return &RuntimeError{
523				Class: contract.ErrorClassAdapterTimeout,
524				Err:   fmt.Errorf("%w: send: %s", ErrAdapterTimeout, err.Error()),
525			}
526		}
527		return classifyTransportError(err)
528	}
