530	// classifyTransportError wraps a transport-layer error in a
531	// RuntimeError, attaching stderr_tail when available.
532	func classifyTransportError(err error) *RuntimeError {
533		if err == nil {
534			return nil
535		}
536		rt := &RuntimeError{
537			Class: contract.ErrorClassAdapterPanic,
538			Err:   err,
539		}
540		var sxerr *SubprocessExitError
541		if errors.As(err, &sxerr) {
542			rt.ExitCode = sxerr.ExitCode
543			rt.StderrTail = sxerr.StderrTail
544		}
545		return rt
546	}
547	
548	// resolveTimeouts fills zero fields in the supplied timeout struct
549	// from DefaultSubprocessTimeouts. Pure function so it's trivial to
550	// test in isolation.
551	func resolveTimeouts(t SubprocessTimeouts) SubprocessTimeouts {
552		d := DefaultSubprocessTimeouts()
553		if t.Handshake == 0 {
554			t.Handshake = d.Handshake
555		}
556		if t.Emit == 0 {
557			t.Emit = d.Emit
558		}
559		if t.Shutdown == 0 {
560			t.Shutdown = d.Shutdown
561		}
