package adapterkit

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"sync/atomic"
	"time"
)

// ScriptedResponder is a convenience for building a Server from
// typed test hooks.
type ScriptedResponder struct {
	DeclaredOutputs []DeclaredOutput
	ConceptKinds    map[string]CapabilityLevel

	RespondToInitialize func(ctx context.Context, received InitializeParams) (InitializeResult, *Error)
	RespondToEmit       func(ctx context.Context, received EmitParams) (EmitResult, *Error)
	RespondToShutdown   func(ctx context.Context) *Error
}

func (r *ScriptedResponder) AsServer(name, version string) *Server {
	server := NewServer(ServerOptions{Name: name, Version: version})
	server.OnInitialize(func(ctx context.Context, received InitializeParams) (InitializeResult, error) {
		if r.RespondToInitialize != nil {
			result, rpcErr := r.RespondToInitialize(ctx, received)
			if rpcErr != nil {
				return InitializeResult{}, rpcErr
			}
			return result, nil
		}
		conceptKinds := r.ConceptKinds
		if conceptKinds == nil {
			conceptKinds = map[string]CapabilityLevel{}
		}
		declaredOutputs := r.DeclaredOutputs
		if declaredOutputs == nil {
			declaredOutputs = []DeclaredOutput{}
		}
		return InitializeResult{
			Server:          name + "/" + version,
			ProtocolVersion: ContractVersionV1,
			Capabilities: Capabilities{
				ConceptKinds:   conceptKinds,
				WriteToolOwned: true,
			},
			DeclaredOutputs: declaredOutputs,
		}, nil
	})
	server.OnEmit(func(ctx context.Context, received EmitParams) (EmitResult, error) {
		if r.RespondToEmit == nil {
			return EmitResult{OpsPerformed: []OpRecord{}}, nil
		}
		result, rpcErr := r.RespondToEmit(ctx, received)
		if rpcErr != nil {
			return EmitResult{}, rpcErr
		}
		return result, nil
	})
	server.OnShutdown(func(ctx context.Context) error {
		if r.RespondToShutdown == nil {
			return nil
		}
		rpcErr := r.RespondToShutdown(ctx)
		if rpcErr != nil {
			return rpcErr
		}
		return nil
	})
	return server
}

// SynthesizeInitResult marshals an InitializeResult for tests that want a
// canned response payload without standing up a full Server. Returns the
// marshal error so callers see when caps.Meta or outputs[*].Meta contain
// values that round-trip through json.RawMessage but fail json.Marshal
// (e.g. invalid UTF-8 inside a json.RawMessage placeholder).
func SynthesizeInitResult(name, version string, caps Capabilities, outputs []DeclaredOutput) ([]byte, error) {
	result := InitializeResult{
		Server:          name + "/" + version,
		ProtocolVersion: ContractVersionV1,
		Capabilities:    caps,
		DeclaredOutputs: outputs,
	}
	data, err := json.Marshal(result)
	if err != nil {
		return nil, fmt.Errorf("adapterkit: synthesize init result: %w", err)
	}
	return data, nil
}

// Client drives a Server over the in-memory testing transport.
type Client struct {
	r      *frameReader
	w      io.WriteCloser
	nextID atomic.Int64
}

func (c *Client) Initialize(ctx context.Context, params InitializeParams) (InitializeResult, error) {
	var result InitializeResult
	if err := c.call(ctx, MethodInitialize, params, &result); err != nil {
		return InitializeResult{}, err
	}
	return result, nil
}

func (c *Client) Initialized(ctx context.Context) error {
	// The `initialized` notification has no params per the adapter
	// contract. Passing nil here causes marshalRequestEnvelope to omit
	// the params field entirely, matching what internal/adapter/runtime
	// sends on the wire.
	return c.notify(ctx, MethodInitialized, nil)
}

func (c *Client) Emit(ctx context.Context, params EmitParams) (EmitResult, error) {
	var result EmitResult
	if err := c.call(ctx, MethodEmit, params, &result); err != nil {
		return EmitResult{}, err
	}
	return result, nil
}

func (c *Client) Shutdown(ctx context.Context) error {
	var result ShutdownResult
	return c.call(ctx, MethodShutdown, ShutdownParams{}, &result)
}

func (c *Client) notify(ctx context.Context, method string, params any) error {
	if err := ctx.Err(); err != nil {
		return err
	}
	payload, err := marshalRequestEnvelope(nil, method, params)
	if err != nil {
		return err
	}
	// Notifications are fire-and-forget — there is no response to wait
	// for. A pre-write ctx check is sufficient; once the bytes hand off
	// to the pipe the call returns immediately.
	return writeFrame(c.w, payload)
}

// readResult is the value the read goroutine in call delivers back to
// the caller: either a parsed frame or the error that terminated the
// read.
type readResult struct {
	frame []byte
	err   error
}

func (c *Client) call(ctx context.Context, method string, params any, into any) error {
	if err := ctx.Err(); err != nil {
		return err
	}
	id := c.nextID.Add(1)
	rawID := json.RawMessage(fmt.Appendf(nil, "%d", id))
	payload, err := marshalRequestEnvelope(rawID, method, params)
	if err != nil {
		return err
	}
	if err := writeFrame(c.w, payload); err != nil {
		return err
	}

	// Spawn a goroutine to perform the blocking read so we can select
	// on ctx.Done(). Same pattern used by InprocTransport.Close in
	// internal/adapter/inproc.go: a buffered channel guarantees the
	// goroutine can always send (even if the caller has abandoned the
	// wait), so the goroutine never leaks past the next server frame.
	//
	// Note: cancelling here returns ctx.Err() but the abandoned read
	// goroutine continues running in the background. The Client may be
	// in an unusable state until the server eventually responds (the
	// buffered send drains the result silently). Tests should treat a
	// ctx-cancelled call as fatal to the Client.
	resultCh := make(chan readResult, 1)
	go func() {
		frame, err := c.r.Read(DefaultMaxFrameBytes)
		resultCh <- readResult{frame: frame, err: err}
	}()

	var frame []byte
	select {
	case res := <-resultCh:
		if res.err != nil {
			return res.err
		}
		frame = res.frame
	case <-ctx.Done():
		return ctx.Err()
	}

	resp, err := parseResponseEnvelope(frame)
	if err != nil {
		return err
	}
	if resp.Error != nil {
		return resp.Error
	}
	if into == nil {
		return nil
	}
	if err := json.Unmarshal(resp.Result, into); err != nil {
		return err
	}
	return nil
}

type responseEnvelope struct {
	ID     json.RawMessage `json:"id"`
	Result json.RawMessage `json:"result"`
	Error  *Error          `json:"error"`
}

func marshalRequestEnvelope(id json.RawMessage, method string, params any) ([]byte, error) {
	type envelope struct {
		JSONRPC string          `json:"jsonrpc"`
		ID      json.RawMessage `json:"id,omitempty"`
		Method  string          `json:"method"`
		Params  json.RawMessage `json:"params,omitempty"`
	}

	var paramsRaw json.RawMessage
	if params != nil {
		data, err := json.Marshal(params)
		if err != nil {
			return nil, err
		}
		paramsRaw = data
	}
	return json.Marshal(envelope{
		JSONRPC: JSONRPCVersion,
		ID:      id,
		Method:  method,
		Params:  paramsRaw,
	})
}

func parseResponseEnvelope(data []byte) (responseEnvelope, error) {
	var resp responseEnvelope
	if err := json.Unmarshal(data, &resp); err != nil {
		return responseEnvelope{}, err
	}
	return resp, nil
}

type testReporter interface {
	Helper()
	Fatal(args ...any)
	Fatalf(format string, args ...any)
}

func RunInprocServer(t testReporter, server *Server) (*Client, func()) {
	t.Helper()

	rtToAdapterR, rtToAdapterW := io.Pipe()
	adapterToRtR, adapterToRtW := io.Pipe()
	ctx, cancel := context.WithCancel(context.Background())
	errCh := make(chan error, 1)

	server.stdin = rtToAdapterR
	server.stdout = adapterToRtW
	server.stderr = io.Discard
	server.getenv = func(string) string { return "0123456789abcdef0123456789abcdef" }

	go func() {
		errCh <- server.Run(ctx)
	}()

	client := &Client{
		r: newFrameReader(adapterToRtR),
		w: rtToAdapterW,
	}

	cleanup := func() {
		cancel()
		_ = rtToAdapterW.Close()
		_ = adapterToRtW.Close()
		if err := <-errCh; err != nil &&
			ExitCode(err) == 0 &&
			!errors.Is(err, context.Canceled) &&
			!errors.Is(err, io.ErrClosedPipe) {
			t.Fatalf("server.Run: %v", err)
		}
	}

	return client, cleanup
}

func AssertProtocolShutdownAcked(t testReporter, server *Server) {
	t.Helper()
	deadline := time.Now().Add(100 * time.Millisecond)
	for {
		if server.protocolShutdownAcked() {
			return
		}
		if time.Now().After(deadline) {
			t.Fatal("server did not acknowledge protocol shutdown")
			return
		}
		time.Sleep(time.Millisecond)
	}
}

package adapter

import (
	"context"
	"errors"
	"fmt"
	"io"
	"sync"

	"github.com/aienvs/aienvs/internal/adapter/contract"
)

// InprocTransport runs a BundledAdapter in a goroutine, plumbing its
// stdin / stdout via io.Pipe pairs. The adapter speaks the same wire
// protocol as a subprocess — same FrameReader, same JSON-RPC envelope.
// The runtime cannot tell them apart by behavior.
//
// Concurrency: a single dedicated reader goroutine pumps inbound
// frames into a bounded channel. Recv just selects on that channel +
// ctx. There is never more than one goroutine touching the
// FrameReader's bufio.Reader, so ctx cancellation in one Recv call
// does not race with a subsequent Recv (which is the common case
// during teardown — Emit cancels, then Shutdown's Recv runs).
type InprocTransport struct {
	bundled *BundledAdapter

	// runtime → adapter
	rtToAd *io.PipeWriter
	adIn   *io.PipeReader

	// adapter → runtime
	adToRt *io.PipeWriter
	rtIn   *io.PipeReader

	frameRead *contract.FrameReader
	frameMax  int64

	// frames is the channel the dedicated reader goroutine pushes
	// inbound frames into. Capacity 1 — the protocol is request-
	// response, so buffering more than one frame doesn't help and
	// could mask a runtime that's not draining.
	//
	// closedCh is closed by Close (under closeOnce) before joining
	// readerDone, so the reader goroutine can break out of a blocking
	// channel send when nobody is consuming. Without it, Close would
	// deadlock: readerDone only closes when readLoop returns, and
	// readLoop is blocked on `frames <- ...` when no Recv is listening.
	frames   chan frameOrError
	closedCh chan struct{}

	// runDone is closed when the bundled adapter's Run returns.
	// readerDone is closed when the reader goroutine exits.
	runDone    chan struct{}
	readerDone chan struct{}
	runErr     error

	// closeOnce guards Close so concurrent callers don't both try to
	// reap the bundled adapter goroutine. closeDone is closed at the
	// end of Close's Do body so concurrent callers wait for the first
	// to finish populating closeErr before reading it.
	closeOnce sync.Once
	closeErr  error
	closeDone chan struct{}
}

type frameOrError struct {
	payload []byte
	err     error
}

// NewInprocTransport launches the bundled adapter in a goroutine and
// returns the connected transport.
func NewInprocTransport(ctx context.Context, bundled *BundledAdapter) (*InprocTransport, error) {
	if bundled == nil {
		return nil, errors.New("adapter: NewInprocTransport: bundled is nil")
	}
	if bundled.Run == nil {
		return nil, errors.New("adapter: NewInprocTransport: bundled.Run is nil")
	}

package adapter

import (
	"context"
	"fmt"

	"github.com/aienvs/aienvs/internal/adapter/contract"
)

// SessionOptions configures an AdapterSession at construction. All
// fields are optional; zero values yield runtime defaults.
type SessionOptions struct {
	// WorkspaceRoot is the absolute path the adapter is operating
	// within. Sent in InitializeParams; the adapter uses it to scope
	// declared_outputs.
	WorkspaceRoot string

	// IRVersion is the IR version the runtime is using. v1 only in
	// PR 2; future versions ride additively under capabilities.
	IRVersion string

	// Timeouts overrides DefaultSubprocessTimeouts on a per-session
	// basis. Zero fields fall back to defaults.
	Timeouts SubprocessTimeouts
}

// NewSession constructs a new AdapterSession from a discovered Adapter.
// Spawns the transport (subprocess or inproc) and prepares it for the
// initialize handshake. Does NOT call Initialize — the caller drives
// the four-phase lifecycle.
func (a *Adapter) NewSession(ctx context.Context, opts SessionOptions) (*AdapterSession, error) {
	if opts.IRVersion == "" {
		opts.IRVersion = "v1"
	}

	var tr Transport
	var cookie string
	switch a.Source {
	case SourceBundled:
		if a.Bundled == nil {
			return nil, fmt.Errorf("adapter: bundled adapter %q has no Run callback", a.Manifest.Name)
		}
		ipt, err := NewInprocTransport(ctx, a.Bundled)
		if err != nil {
			return nil, fmt.Errorf("adapter: bundled %q: %w", a.Manifest.Name, err)
		}
		tr = ipt
		cookie = "" // bundled adapters share process; no cookie required
	default:
		sp, c, err := Spawn(ctx, SpawnOptions{
			Manifest: a.Manifest,
			Timeouts: opts.Timeouts,
		})
		if err != nil {
			return nil, err
		}
		tr = sp
		cookie = c
	}

	return &AdapterSession{
		adapter:    a,
		transport:  tr,
		cookie:     cookie,
		ids:        contract.NewIDCorrelator(),
		options:    opts,
		state:      sessionStateNew,
		gateChecks: map[contract.OpKind]bool{},
	}, nil
}

// AdapterSession is one initialize→initialized→emit→shutdown lifecycle
// against a single adapter. Single-goroutine usage; the orchestrator
// drives all method calls from the same goroutine. The transport may
// use its own goroutines internally (subprocess stderr drainer, inproc
// Run goroutine), but those don't race with the session's state.
type AdapterSession struct {
	adapter   *Adapter
	transport Transport
	cookie    string
	ids       *contract.IDCorrelator
	options   SessionOptions

	// state tracks where we are in the four-phase lifecycle. Methods
	// that don't match the current state return
	// ErrAdapterProtocolOrderViolation.
	state sessionState

	// initResult is captured from the adapter's initialize response;
	// declared_outputs feeds the integrity gate.
	initResult *contract.InitializeResult

	// gateChecks records which kinds were declared "supported" — used
	// by capability-lied detection after Emit.
	gateChecks map[contract.OpKind]bool
}

type sessionState uint8

const (
	sessionStateNew sessionState = iota
	sessionStateInitialized
	sessionStateEmitting
	sessionStateClosed
)

// Manifest returns the adapter's manifest. Read-only.
func (s *AdapterSession) Manifest() AdapterManifest {
	return s.adapter.Manifest
}

// StderrTail returns a snapshot of the adapter's stderr ring buffer.
// nil for inproc adapters.
func (s *AdapterSession) StderrTail() []byte {
	return s.transport.StderrTail()
}

// Pending returns the IDCorrelator's in-flight count. Useful for
// observability and for asserting no leaks at session teardown.
func (s *AdapterSession) Pending() int {
	return s.ids.Pending()
}

