// importing errors at every test call site.
func errorsAs(err error, target any) bool {
	type asAware interface {
		As(any) bool
	}
	_ = asAware(nil)
	if err == nil {
		return false
	}
	if e, ok := err.(*adapterkit.Error); ok {
