100	// .claude/skills/aienvs-<id>/templates/foo.txt. We do not emit
101	// per-asset-parent mkdirs; the sync engine creates intermediate
102	// directories as part of write_file execution. (Echo reference
103	// adapter emits at most one mkdir per emit; we mirror that.)
104	func emitSkill(emitted *emittedOps, node irNode) error {
105		body, err := nodeBodyBytes(node)
106		if err != nil {
107			return wrapBodyErr(node, err)
108		}
109	
110		skillDir := skillsParent + "/" + skillPrefix + node.ID
111		emitted.add(adapterkit.OpMkdir{Path: skillDir, Mode: 0o755})
112	
113		skillPath := skillDir + "/SKILL.md"
114		wf, err := adapterkit.NewOpWriteFile(skillPath, 0o644, prependHeader(body))
115		if err != nil {
116			return wrapOpErr(node, err)
117		}
118		if _, err := json.Marshal(wf); err != nil {
119			return wrapOpErr(node, err)
120		}
121		emitted.add(wf)
122	
123		// Sort assets by RelPath for deterministic output ordering.
124		assets := append([]irAsset(nil), node.Assets...)
125		sort.Slice(assets, func(i, j int) bool { return assets[i].RelPath < assets[j].RelPath })
126	
127		for _, a := range assets {
128			if a.RelPath == "" {
129				return &adapterkit.Error{
130					Code:    adapterkit.CodeInvalidParams,
131					Message: fmt.Sprintf("claude: skill %q has asset with empty rel_path", node.ID),
132				}
133			}
134			assetBody, err := assetBodyBytes(a)
135			if err != nil {
136				return &adapterkit.Error{
137					Code:    adapterkit.CodeInvalidParams,
138					Message: fmt.Sprintf("claude: skill %q asset %q body: %s", node.ID, a.RelPath, err.Error()),
139				}
140			}
141			assetPath := skillDir + "/" + a.RelPath
142			op, err := adapterkit.NewOpWriteFile(assetPath, 0o644, assetBody)
143			if err != nil {
144				return &adapterkit.Error{
145					Code:    adapterkit.CodeInvalidParams,
146					Message: fmt.Sprintf("claude: skill %q asset %q: %s", node.ID, a.RelPath, err.Error()),
147				}
148			}
149			if _, err := json.Marshal(op); err != nil {
150				return &adapterkit.Error{
151					Code:    adapterkit.CodeInvalidParams,
152					Message: fmt.Sprintf("claude: skill %q asset %q marshal: %s", node.ID, a.RelPath, err.Error()),
153				}
154			}
155			emitted.add(op)
156		}
157		return nil
158	}
