160	// ensureSubdir adds the per-emit mkdir + README pair for a reserved
161	// subdirectory once per emit call. Subsequent calls are no-ops.
162	func ensureSubdir(emitted *emittedOps, subdir string, seen map[string]bool) {
163		if seen[subdir] {
164			return
165		}
166		seen[subdir] = true
