11	)
12	
13	// irNode is the wire-side shape of one IR node delivered via
14	// EmitParams.IR. The adapter does not import internal/ir's Node
15	// directly because that type carries decoder-internal fields the
16	// wire payload doesn't include.
17	type irNode struct {
18		ID         string          `json:"id"`
19		Kind       string          `json:"kind"`
20		Version    int             `json:"version,omitempty"`
21		Required   bool            `json:"required,omitempty"`
22		Targets    []string        `json:"targets,omitempty"`
23		Provenance irProvenance    `json:"provenance,omitempty"`
24		Body       json.RawMessage `json:"body,omitempty"`
25		Assets     []irAsset       `json:"assets,omitempty"`
26	}
27	
28	type irProvenance struct {
29		Path    string `json:"path,omitempty"`
30		BlobSHA string `json:"blob_sha,omitempty"`
31	}
32	
33	type irAsset struct {
34		RelPath    string          `json:"rel_path"`
35		Provenance irProvenance    `json:"provenance,omitempty"`
36		Content    json.RawMessage `json:"content,omitempty"`
37	}
38	
39	type irDocument struct {
40		Nodes []irNode `json:"nodes"`
41	}
42	
