			} else {
				sawClaudeMDSection = true
			}
		}
	}
	if !sawMCPPointer {
		t.Error(".mcp.json locator not asserted")
	}
	if !sawClaudeMDSection {
		t.Error("CLAUDE.md locator not asserted")
	}
}

