		contract.OpKind("rule"): true,
	}

	// Build {"nodes":[{"id":"n0","kind":"agent"},...,{"id":"n9999","kind":"agent"}]}.
	// None of the kinds match — function must return false without
	// retaining the full node tree.
	var b strings.Builder
	b.WriteString(`{"nodes":[`)
